  1→//! Behavior specification output for explored functions.
  2→//!
  3→//! A [`FunctionSpec`] captures the complete behavioral specification of a function:
  4→//! equivalence classes grouped by branch path, preconditions, postconditions,
  5→//! concrete examples, and provenance (proven vs observed). The spec can be
  6→//! rendered as human-readable markdown, machine-readable JSON, or YAML with
  7→//! property descriptions.
  8→
  9→use std::collections::HashSet;
 10→use std::fmt;
 11→use std::fs;
 12→use std::path::Path;
 13→
 14→use serde::{Deserialize, Serialize};
 15→
 16→use crate::coverage_metrics::DiscoveryMethod;
 17→use crate::equivalence::{BranchPath, EquivalenceClass, Precondition};
 18→use crate::execution_record::{ErrorInfo, SideEffect};
 19→use crate::explorer::ObservationOutput;
 20→use crate::fingerprint::compute_deep_fingerprints;
 21→use crate::invariants::{ClassifiedInvariant, InvariantKind};
 22→use crate::protocol::FunctionAnalysis;
 23→
 24→/// Error type for spec bundle I/O operations.
 25→#[derive(Debug)]
 26→pub enum SpecIoError {
 27→    /// Filesystem I/O error.
 28→    Io(std::io::Error),
 29→    /// JSON serialization or deserialization error.
 30→    Json(serde_json::Error),
 31→}
 32→
 33→impl fmt::Display for SpecIoError {
 34→    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
 35→        match self {
 36→            Self::Io(e) => write!(f, "spec I/O error: {e}"),
 37→            Self::Json(e) => write!(f, "spec JSON error: {e}"),
 38→        }
 39→    }
 40→}
 41→
 42→impl std::error::Error for SpecIoError {
 43→    fn source(&self) -> Option<&(dyn std::error::Error + 'static)> {
 44→        match self {
 45→            Self::Io(e) => Some(e),
 46→            Self::Json(e) => Some(e),
 47→        }
 48→    }
 49→}
 50→
 51→impl From<std::io::Error> for SpecIoError {
 52→    fn from(e: std::io::Error) -> Self {
 53→        Self::Io(e)
 54→    }
 55→}
 56→
 57→impl From<serde_json::Error> for SpecIoError {
 58→    fn from(e: serde_json::Error) -> Self {
 59→        Self::Json(e)
 60→    }
 61→}
 62→
 63→/// Whether a property was proven by constraint solving or merely observed.
 64→#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
 65→#[serde(rename_all = "snake_case")]
 66→pub enum Provenance {
 67→    /// Confirmed by Z3 constraint solving — holds for all inputs on this path.
 68→    Proven,
 69→    /// Observed across all sampled inputs but not formally proven.
 70→    Observed,
 71→}
