 77→/// High-level category for an invariant property description.
 78→#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
 79→#[serde(rename_all = "snake_case")]
 80→pub enum InvariantCategory {
 81→    NumericBound,
